mapper.select:
SELECT id, sender_id AS senderId, receiver_id AS receiverId,
content, message_type AS messageType, image_url AS imageUrl,
status, create_time AS createTime
FROM biz_private_message
WHERE ((sender_id = #{currentUserId} AND receiver_id = #{peerId} AND sender_deleted = 0)
OR (sender_id = #{peerId} AND receiver_id = #{currentUserId} AND receiver_deleted = 0))

    AND create_time > #{clearBeforeTime}


    AND id < #{lastMessageId}

ORDER BY id DESC
LIMIT #{pageSize}

mapper.update:
UPDATE biz_private_message
SET status = 1
WHERE sender_id = #{peerId}
  AND receiver_id = #{currentUserId}
  AND status = 0
  AND receiver_deleted = 0
